    /**
     * Converts this Stream to a JDK Stream.
     * This is an intermediate operation that creates a java.util.stream.Stream containing the same elements.
     *
     * <p>This operation is useful when you need to integrate with APIs that expect JDK streams
     * or when you want to use JDK stream operations not available in this Stream implementation.
     * The returned stream is parallel if this stream is parallel; encounter order is preserved.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * java.util.stream.Stream<String> jdkStream = Stream.of("a", "b", "c")
     *                                                   .toJdkStream();
     * // Can now use JDK stream operations
     * jdkStream.forEach(System.out::println);
     * }</pre>
     *
     * @return a java.util.stream.Stream containing the elements of this Stream
     * @see #transformB(Function)
     * @see #transformB(Function, boolean)
     */
    @SequentialOnly
    @IntermediateOp
    public abstract java.util.stream.Stream<T> toJdkStream();

    /**
     * Transforms the current Stream into another Stream by applying the provided function.
     * The function takes a JDK Stream as input and returns a new JDK Stream.
     * The returned JDK Stream is then wrapped back into a Stream of this class.
     *
     * <p>This operation allows you to leverage JDK stream operations while maintaining
     * the current Stream API. The transformation is not deferred by default.
     * The operation is sequential and cannot be parallelized.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Stream<Integer> result = Stream.of(1, 2, 3, 4, 5)
     *     .transformB(jdkStream -> jdkStream
     *         .filter(x -> x % 2 == 0)
     *         .map(x -> x * 2));
     * // result contains: [4, 8]
     * }</pre>
     *
     * @param <U> The type of elements in the returned stream
     * @param transfer the function to be applied on the current stream to produce a new stream.
     * @return a new Stream transformed by the provided function
     * @throws IllegalStateException if the stream has already been operated upon or closed
     * @throws IllegalArgumentException if the provided function is {@code null}
     * @see #toJdkStream()
     */
    @Beta
    @SequentialOnly
    @IntermediateOp
    public <U> Stream<U> transformB(final Function<? super java.util.stream.Stream<T>, ? extends java.util.stream.Stream<? extends U>> transfer)
            throws IllegalArgumentException {

        return transformB(transfer, false);
    }

    /**
     * Transforms the current Stream into another Stream by applying the provided function.
     * The function takes a JDK Stream as input and returns a new JDK Stream.
     * The returned JDK Stream is then wrapped back into a Stream of this class.
     * The transformation can be deferred, which means it will be performed when the stream is consumed.
     *
     * <p>When deferred is {@code true}, the transformation is lazy and will only be executed when
     * terminal operations are called. When {@code false}, the transformation is applied immediately.
     * The operation is sequential and cannot be parallelized.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * // Deferred transformation
     * Stream<String> result = Stream.of("hello", "world")
     *     .transformB(jdkStream -> jdkStream
     *         .map(String::toUpperCase)
     *         .sorted(), true);
     * // Transformation happens when terminal operation is called
     * result.toList();   // returns ["HELLO", "WORLD"]
     * }</pre>
     *
     * @param <U> The type of elements in the returned stream
     * @param transfer the function to be applied on the current stream to produce a new stream.
     * @param deferred if {@code true}, the transformation is deferred until the stream is consumed
     * @return a new Stream transformed by the provided function
     * @throws IllegalStateException if the stream has already been operated upon or closed
     * @throws IllegalArgumentException if the provided function is {@code null}
     * @see #toJdkStream()
     */
    @Beta
    @SequentialOnly
    @IntermediateOp
    public <U> Stream<U> transformB(final Function<? super java.util.stream.Stream<T>, ? extends java.util.stream.Stream<? extends U>> transfer,
            final boolean deferred) throws IllegalStateException, IllegalArgumentException {
        assertNotClosed();
        checkArgNotNull(transfer, cs.transfer);

        if (deferred) {
            final Supplier<Stream<U>> delayInitializer = () -> Stream.from(transfer.apply(this.toJdkStream()));
            return Stream.defer(delayInitializer);
        } else {
            return Stream.from(transfer.apply(this.toJdkStream()));
        }
    }

    abstract ObjIteratorEx<T> iteratorEx();

    /**
     * Temporarily switches the stream to a parallel stream for the operation {@code op} and then switches back to a sequential stream.
     * This method is useful for performing a specific operation in parallel while keeping the rest of the stream operations sequential.
     *
     * <p>The stream is split into chunks of the specified size, processed in parallel using multiple threads,
     * and then the results are flattened back into a sequential stream. This allows for selective parallelization
     * of expensive operations without making the entire stream parallel.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * // Process chunks of 100 elements in parallel using 4 threads
     * Stream<Integer> result = Stream.of(largeList)
     *     .sps(4, 100, chunk -> Stream.of(chunk)
     *         .map(expensiveOperation)
     *         .filter(x -> x > 0));
     * }</pre>
     *
     * <p><b>Implementation Note:</b> it's equivalent to: {@code split(chunkSize).parallel(maxThreadNum).flatMap(op::apply).sequential()}
     *
     * @param <R> The type of elements in the returned stream
     * @param maxThreadNum the maximum number of threads to be used for the parallel operation. Must be positive.
     * @param chunkSize the chunk size this stream will be split into for the parallel operation. Must be positive.
     * @param op the operation applied to each chunk of elements, producing a new Stream; applied repeatedly by multiple threads in parallel.
     * @return a new Stream transformed by the provided function
     * @throws IllegalArgumentException if the specified maxThreadNum or chunkSize is equal to or less than 0
     */
    @Beta
    @IntermediateOp
    public <R> Stream<R> sps(final int maxThreadNum, final int chunkSize, final Function<? super List<T>, ? extends Stream<? extends R>> op)
            throws IllegalArgumentException {
        assertNotClosed();
        checkArgPositive(maxThreadNum, cs.maxThreadNum);
        checkArgPositive(chunkSize, cs.chunkSize);

        if (isParallel() && maxThreadNum == maxThreadNum()) {
            //noinspection resource
            return split(chunkSize).flatMap(op::apply).sequential();
        } else {
            final AsyncExecutor asyncExecutor = asyncExecutor();
            final int checkedMaxThreadNum = checkMaxThreadNum(maxThreadNum, asyncExecutor);

            //noinspection resource
            return split(chunkSize).parallel(checkedMaxThreadNum, splitor(), asyncExecutor, cancelUncompletedThreads()).flatMap(op::apply).sequential();
        }
    }

