    /**
     * Splits the given string into lines and returns a stream of the resulting lines.
     * This is a static factory method that creates a stream of lines from a string.
     *
     * <p>Line terminators recognized are line feed "\n" (LF), carriage return "\r" (CR),
     * and carriage return followed immediately by a line feed "\r\n" (CRLF).
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Stream<String> lines = Stream.splitToLines("line1\nline2\rline3\r\nline4");
     * lines.forEach(System.out::println);   // prints: line1, line2, line3, line4
     * }</pre>
     *
     * @param str the string to be split into lines
     * @return a stream of lines resulting from splitting the input string
     */
    @Beta
    public static Stream<String> splitToLines(final String str) {
        return lineSplitter.splitToStream(str);
    }

    /**
     * Splits the given string into lines and returns a stream of the resulting lines.
     * This is a static factory method that creates a stream of lines with optional trimming and filtering.
     *
     * <p>Line terminators recognized are line feed "\n" (LF), carriage return "\r" (CR),
     * and carriage return followed immediately by a line feed "\r\n" (CRLF).
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Stream<String> lines = Stream.splitToLines("  line1  \n\n  line2  ", true, true);
     * lines.forEach(System.out::println);   // prints: line1, line2 (trimmed, empty line omitted)
     * }</pre>
     *
     * @param str the string to be split into lines
     * @param trim whether to trim each line
     * @param omitEmptyLines whether to omit empty lines
     * @return a stream of lines resulting from splitting the input string
     */
    @Beta
    public static Stream<String> splitToLines(final String str, final boolean trim, final boolean omitEmptyLines) {
        if (trim) {
            if (omitEmptyLines) {
                return trimAndOmitEmptyLinesLineSplitter.splitToStream(str);
            } else {
                return trimLineSplitter.splitToStream(str);
            }
        } else if (omitEmptyLines) {
            return omitEmptyLinesLineSplitter.splitToStream(str);
        } else {
            return lineSplitter.splitToStream(str);
        }
    }

    /**
     * Splits the total size into chunks based on the specified maximum chunk count.
     * This is a static factory method that creates a stream of mapped chunk values.
     *
     * <p>The size of the chunks is larger first. For example, if totalSize is 10 and maxChunkCount is 3,
     * the chunks will have sizes [4, 3, 3]. The length of returned Stream may be less than the specified
     * maxChunkCount if the input totalSize is less than maxChunkCount.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * int[] array = {1, 2, 3, 4, 5, 6, 7};
     * Stream<int[]> chunks = Stream.splitByChunkCount(7, 3,
     *     (from, to) -> Arrays.copyOfRange(array, from, to));
     * chunks.forEach(chunk -> System.out.println(Arrays.toString(chunk)));
     * // Prints: [1, 2, 3], [4, 5], [6, 7]
     * }</pre>
     *
     * @param <T> the type of the elements in the resulting stream
     * @param totalSize the total size to be split. It could be the size of an array, list, etc.
     * @param maxChunkCount the maximum number of chunks to split into
     * @param mapper a function to map the chunk from and to index to an element in the resulting stream
     * @return a Stream of the mapped chunk values
     * @throws IllegalArgumentException if totalSize is negative or maxChunkCount is not positive
     * @see #splitByChunkCount(int, int, boolean, IntBiFunction)
     */
    public static <T> Stream<T> splitByChunkCount(final int totalSize, final int maxChunkCount, final IntBiFunction<? extends T> mapper) {
        return splitByChunkCount(totalSize, maxChunkCount, false, mapper);
    }

    /**
     * Splits the total size into chunks based on the specified maximum chunk count.
     * This is a static factory method that creates a stream of mapped chunk values with configurable chunk size ordering.
     *
     * <p>The size of the chunks can be either smaller or larger first based on the flag.
     * The length of returned Stream may be less than the specified maxChunkCount if the input totalSize is less than maxChunkCount.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * final int[] a = Array.rangeClosed(1, 7);
     * splitByChunkCount(7, 5, true, (fromIndex, toIndex) ->  copyOfRange(a, fromIndex, toIndex));    // [[1], [2], [3], [4, 5], [6, 7]]
     * splitByChunkCount(7, 5, false, (fromIndex, toIndex) ->  copyOfRange(a, fromIndex, toIndex));   // [[1, 2], [3, 4], [5], [6], [7]]
     * }</pre>
     *
     * @param <T> the type of the elements in the resulting stream
     * @param totalSize the total size to be split. It could be the size of an array, list, etc.
     * @param maxChunkCount the maximum number of chunks to split into
     * @param sizeSmallerFirst if {@code true}, smaller chunks will be created first; otherwise, larger chunks will be created first
     * @param mapper a function to map the chunk from and to index to an element in the resulting stream
     * @return a Stream of the mapped chunk values
     * @throws IllegalArgumentException if totalSize is negative or maxChunkCount is not positive
     * @see IntStream#splitByChunkCount(int, int, boolean, IntBinaryOperator)
     */
    public static <T> Stream<T> splitByChunkCount(final int totalSize, final int maxChunkCount, final boolean sizeSmallerFirst,
            final IntBiFunction<? extends T> mapper) {
        N.checkArgNotNegative(totalSize, cs.totalSize);
        N.checkArgPositive(maxChunkCount, cs.maxChunkCount);

        if (totalSize == 0) {
            return Stream.empty();
        }

        final int count = Math.min(totalSize, maxChunkCount);
        final int biggerSize = totalSize % maxChunkCount == 0 ? totalSize / maxChunkCount : totalSize / maxChunkCount + 1;
        final int biggerCount = totalSize % maxChunkCount;
        final int smallerSize = Math.max(totalSize / maxChunkCount, 1);
        final int smallerCount = count - biggerCount;

        ObjIteratorEx<T> iter = null;

        if (sizeSmallerFirst) {
            iter = new ObjIteratorEx<>() {
                private int cnt = 0;
                private int cursor = 0;

                @Override
                public boolean hasNext() {
                    return cursor < totalSize;
                }

                @Override
                public T next() {
                    if (cursor >= totalSize) {
                        throw new NoSuchElementException(InternalUtil.ERROR_MSG_FOR_NO_SUCH_EX);
                    }

                    return mapper.apply(cursor, cursor = (cnt++ < smallerCount ? cursor + smallerSize : cursor + biggerSize));
                }

                @Override
                public void advance(long n) {
                    if (n <= 0) {
                        return;
                    }

                    while (n-- > 0 && cursor < totalSize) {
                        cursor = cnt++ < smallerCount ? cursor + smallerSize : cursor + biggerSize;
                    }
                }

                @Override
                public long count() {
                    final int ret = count - cnt;
                    cnt = count;
                    cursor = totalSize;
                    return ret;
                }
            };
        } else {
            iter = new ObjIteratorEx<>() {
                private int cnt = 0;
                private int cursor = 0;

                @Override
                public boolean hasNext() {
                    return cursor < totalSize;
                }

                @Override
                public T next() {
                    if (cursor >= totalSize) {
                        throw new NoSuchElementException(InternalUtil.ERROR_MSG_FOR_NO_SUCH_EX);
                    }

                    return mapper.apply(cursor, cursor = (cnt++ < biggerCount ? cursor + biggerSize : cursor + smallerSize));
                }

                @Override
                public void advance(long n) {
                    if (n <= 0) {
                        return;
                    }

                    while (n-- > 0 && cursor < totalSize) {
                        cursor = cnt++ < biggerCount ? cursor + biggerSize : cursor + smallerSize;
                    }
                }

                @Override
                public long count() {
                    final int ret = count - cnt;
                    cnt = count;
                    cursor = totalSize;
                    return ret;
                }
            };
        }

        return Stream.of(iter);
    }

    /**
     * Flattens a collection of collections into a single stream of elements.
     * This is a static factory method that creates a stream from nested collections.
     *
     * <p>All elements from all inner collections are combined into a single flat stream.
     * The order of elements follows the iteration order of the outer collection and then the inner collections.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * List<List<Integer>> nested = Arrays.asList(
     *     Arrays.asList(1, 2),
     *     Arrays.asList(3, 4)
     * );
     * Stream<Integer> flat = Stream.flatten(nested);
     * flat.toList();   // returns [1, 2, 3, 4]
     * }</pre>
     *
     * @param <T> the type of elements in the collections
     * @param c the collection of collections to be flattened
     * @return a stream of elements from the flattened collections
     */
    public static <T> Stream<T> flatten(final Collection<? extends Collection<? extends T>> c) {
        return of(c).flatmap(Fn.<Collection<? extends T>> identity());
    }

    /**
     * Flattens a two-dimensional array into a single stream of elements.
     * This is a static factory method that creates a stream from a two-dimensional array.
     *
     * <p>All elements from all inner arrays are combined into a single flat stream.
     * The elements are traversed row by row (horizontally).
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Integer[][] array2D = {{1, 2}, {3, 4}, {5, 6}};
     * Stream<Integer> flat = Stream.flatten(array2D);
     * flat.toList();   // returns [1, 2, 3, 4, 5, 6]
     * }</pre>
     *
     * @param <T> the type of elements in the array
     * @param a the two-dimensional array to be flattened
     * @return a stream of elements from the flattened array
     */
    public static <T> Stream<T> flatten(final T[][] a) {
        return of(a).flatMapArray(Fn.identity());
    }

    /**
     * Flattens a two-dimensional array into a single stream of elements.
     * This is a static factory method that creates a stream from a two-dimensional array with configurable traversal order.
     *
     * <p>All elements from all inner arrays are combined into a single flat stream.
     * The traversal order can be either horizontal (row by row) or vertical (column by column).
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Integer[][] array2D = {{1, 2}, {3, 4}, {5, 6}};
     * Stream<Integer> horizontal = Stream.flatten(array2D, false);
     * horizontal.toList();   // returns [1, 2, 3, 4, 5, 6]
     *
     * Stream<Integer> vertical = Stream.flatten(array2D, true);
     * vertical.toList();   // returns [1, 3, 5, 2, 4, 6]
     * }</pre>
     *
     * @param <T> the type of elements in the array
     * @param a the two-dimensional array to be flattened
     * @param vertically if {@code true}, the array is flattened vertically (column by column); otherwise, it is flattened horizontally (row by row)
     * @return a stream of elements from the flattened array
     */
    public static <T> Stream<T> flatten(final T[][] a, final boolean vertically) {
        if (N.isEmpty(a)) {
            return empty();
        } else if (a.length == 1) {
            return of(a[0]);
        } else if (!vertically) {
            return of(a).flatMapArray(Fn.identity());
        }

        long n = 0;

        for (final T[] e : a) {
            n += N.len(e);
        }

        if (n == 0) {
            return empty();
        }

        final int rows = N.len(a);
        final long count = n;

        final Iterator<T> iter = new ObjIteratorEx<>() {
            private int rowNum = 0;
            private int colNum = 0;
            private long cnt = 0;

            @Override
            public boolean hasNext() {
                return cnt < count;
            }

            @Override
            public T next() {
                if (cnt++ >= count) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                if (rowNum == rows) {
                    rowNum = 0;
                    colNum++;
                }

                while (a[rowNum] == null || colNum >= a[rowNum].length) {
                    if (rowNum < rows - 1) {
                        rowNum++;
                    } else {
                        rowNum = 0;
                        colNum++;
                    }
                }

                return a[rowNum++][colNum];
            }
        };

        return of(iter);
    }

    /**
     * Flattens a two-dimensional array into a single stream of elements with alignment.
     * This is a static factory method that creates a stream from a two-dimensional array with padding for uneven rows/columns.
     *
     * <p>All elements from all inner arrays are combined into a single flat stream.
     * If arrays have different lengths, the valueForAlignment is used to pad shorter arrays.
     * The traversal order can be either horizontal (row by row) or vertical (column by column).
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Integer[][] array2D = {{1, 2, 3}, {4, 5}, {6}};
     * Stream<Integer> aligned = Stream.flatten(array2D, 0, false);
     * aligned.toList();   // returns [1, 2, 3, 4, 5, 0, 6, 0, 0]
     * }</pre>
     *
     * @param <T> the type of elements in the array
     * @param a the two-dimensional array to be flattened
     * @param valueForAlignment the element to append so there are the same number of elements in all rows/columns
     * @param vertically if {@code true}, the array is flattened vertically; otherwise, it is flattened horizontally
     * @return a stream of elements from the flattened array
     */
    public static <T> Stream<T> flatten(final T[][] a, final T valueForAlignment, final boolean vertically) {
        if (N.isEmpty(a)) {
            return empty();
        } else if (a.length == 1) {
            return of(a[0]);
        }

        long n = 0;
        int maxLen = 0;

        for (final T[] e : a) {
            n += N.len(e);
            maxLen = N.max(maxLen, N.len(e));
        }

        if (n == 0) {
            return empty();
        }

        final int rows = N.len(a);
        final int cols = maxLen;
        final long count = (long) rows * cols;
        Iterator<T> iter = null;

        if (vertically) {
            iter = new ObjIteratorEx<>() {
                private int rowNum = 0;
                private int colNum = 0;
                private long cnt = 0;

                @Override
                public boolean hasNext() {
                    return cnt < count;
                }

                @Override
                public T next() {
                    if (cnt++ >= count) {
                        throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                    }

                    if (rowNum == rows) {
                        rowNum = 0;
                        colNum++;
                    }

                    if (a[rowNum] == null || colNum >= a[rowNum].length) {
                        rowNum++;
                        return valueForAlignment;
                    } else {
                        return a[rowNum++][colNum];
                    }
                }
            };
        } else {
            iter = new ObjIteratorEx<>() {

                private int rowNum = 0;
                private int colNum = 0;
                private long cnt = 0;

                @Override
                public boolean hasNext() {
                    return cnt < count;
                }

                @Override
                public T next() {
                    if (cnt++ >= count) {
                        throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                    }

                    if (colNum >= cols) {
                        colNum = 0;
                        rowNum++;
                    }

                    if (a[rowNum] == null || colNum >= a[rowNum].length) {
                        colNum++;
                        return valueForAlignment;
                    } else {
                        return a[rowNum][colNum++];
                    }
                }

            };
        }

        return of(iter);
    }

    /**
     * Flattens a three-dimensional array into a single stream of elements.
     * This is a static factory method that creates a stream from a three-dimensional array.
     *
     * <p>All elements from all inner arrays are combined into a single flat stream.
     * The elements are traversed in the natural order of the array indices.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Integer[][][] array3D = {{{1, 2}, {3, 4}}, {{5, 6}, {7, 8}}};
     * Stream<Integer> flat = Stream.flatten(array3D);
     * flat.toList();   // returns [1, 2, 3, 4, 5, 6, 7, 8]
     * }</pre>
     *
     * @param <T> the type of elements in the array
     * @param a the three-dimensional array to be flattened
     * @return a stream of elements from the flattened array
     */
    public static <T> Stream<T> flatten(final T[][][] a) {
        return of(a).flatMapArray(e -> e).flatMapArray(Fn.identity());
    }

    /**
     * Creates a stream that repeats the given element a specified number of times.
     * This is a static factory method that creates a stream with repeated elements.
     *
     * <p>The returned stream will contain exactly n copies of the specified element.
     * If n is 0, an empty stream is returned.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Stream<String> repeated = Stream.repeat("Hello", 3);
     * repeated.toList();               // returns [Hello, Hello, Hello]
     * Stream.repeat("x", 0).count();   // returns 0
     * }</pre>
     *
     * @param <T> the type of the element
     * @param element the element to be repeated
     * @param n the number of times to repeat the element
     * @return a stream of the repeated element
     * @throws IllegalArgumentException if the number of repetitions is negative
     */
    public static <T> Stream<T> repeat(final T element, final long n) throws IllegalArgumentException {
        N.checkArgNotNegative(n, cs.n);

        if (n == 0) {
            return empty();
        }

        return new IteratorStream<>(new ObjIteratorEx<>() {
            private long cnt = n;

            @Override
            public boolean hasNext() {
                return cnt > 0;
            }

            @Override
            public T next() {
                if (cnt <= 0) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                cnt--;
                return element;
            }

            @Override
            public void advance(final long n) {
                if (n <= 0) {
                    return;
                }

                cnt = n >= cnt ? 0 : cnt - n;
            }

            @Override
            public long count() {
                final long ret = cnt;
                cnt = 0;
                return ret;
            }

            @Override
            public <A> A[] toArray(A[] a) {
                if (cnt > Integer.MAX_VALUE) {
                    throw new IllegalStateException("Cannot create array larger than Integer.MAX_VALUE: " + cnt);
                }

                final int len = (int) cnt;
                a = a.length >= len ? a : N.copyOf(a, len);

                for (int i = 0; i < len; i++) {
                    a[i] = (A) element;
                }

                cnt = 0;

                return nullTerminate(a, len);
            }
        });
    }

    /**
     * Creates a stream that iterates using the given hasNext and next suppliers.
     * This is a static factory method that creates a stream from supplier functions.
     *
     * <p>The stream continues as long as hasNext returns {@code true}. Each element is provided by the next supplier.
     * This is useful for converting imperative iteration patterns into streams.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * int[] counter = {0};
     * Stream<Integer> numbers = Stream.iterate(
     *     () -> counter[0] < 5,
     *     () -> counter[0]++
     * );
     * numbers.forEach(System.out::println);   // prints: 0, 1, 2, 3, 4
     * }</pre>
     *
     * @param <T> the type of elements in the stream
     * @param hasNext a BooleanSupplier that returns {@code true} if the iteration should continue
     * @param next a Supplier that provides the next element in the iteration
     * @return a stream of elements generated by the iteration
     * @throws IllegalArgumentException if hasNext or next is null
     */
    public static <T> Stream<T> iterate(final BooleanSupplier hasNext, final Supplier<? extends T> next) throws IllegalArgumentException {
        N.checkArgNotNull(hasNext);
        N.checkArgNotNull(next);

        return of(new ObjIteratorEx<>() {
            private boolean hasNextVal = false;

            @Override
            public boolean hasNext() {
                if (!hasNextVal) {
                    hasNextVal = hasNext.getAsBoolean();
                }

                return hasNextVal;
            }

            @Override
            public T next() {
                if (!hasNextVal && !hasNext()) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                hasNextVal = false;
                return next.get();
            }
        });
    }

    /**
     * Returns a Stream produced by iterative application of a function to an initial element.
     * This is a static factory method that creates a stream through iterative function application.
     *
     * <p>The first element (position 0) in the Stream will be the provided init value.
     * For n &gt; 0, the element at position n will be the result of applying the function f to the
     * element at position n - 1. The stream continues as long as hasNext returns {@code true}.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Stream<Integer> powers = Stream.iterate(1, () -> true, x -> x * 2);
     * powers.limit(5).forEach(System.out::println);   // prints: 1, 2, 4, 8, 16
     * }</pre>
     *
     * @param <T> the type of elements in the stream
     * @param init the initial element
     * @param hasNext a supplier that returns {@code true} if the iteration should continue
     * @param f a function to apply to the previous element to generate the next element
     * @return a stream of elements generated by the iteration
     * @throws IllegalArgumentException if the initial element, hasNext or f is null
     */
    public static <T> Stream<T> iterate(final T init, final BooleanSupplier hasNext, final UnaryOperator<T> f) throws IllegalArgumentException {
        N.checkArgNotNull(init);
        N.checkArgNotNull(hasNext);
        N.checkArgNotNull(f);

        return of(new ObjIteratorEx<>() {
            private T cur = (T) NONE;
            private boolean hasNextVal = false;

            @Override
            public boolean hasNext() {
                if (!hasNextVal) {
                    hasNextVal = hasNext.getAsBoolean();
                }

                return hasNextVal;
            }

            @Override
            public T next() {
                if (!hasNextVal && !hasNext()) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                hasNextVal = false;
                return cur = (cur == NONE ? init : f.apply(cur));
            }
        });
    }

    /**
     * Creates a stream that iterates from an initial value, applying a function to generate subsequent values.
     * This is a static factory method that creates a stream through iterative function application with predicate control.
     *
     * <p>The iteration continues as long as the predicate is satisfied. The predicate is tested on the
     * value that would be returned, so the first element is init (if it satisfies the predicate).
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Stream<Integer> numbers = Stream.iterate(1, x -> x < 10, x -> x + 2);
     * numbers.forEach(System.out::println);   // prints: 1, 3, 5, 7, 9
     * }</pre>
     *
     * @param <T> the type of elements in the stream
     * @param init the initial value
     * @param hasNext tests if there is a next element by {@code hasNext.test(init)} for the first time and {@code hasNext.test(f.apply(previous))} for the remaining
     * @param f a function to apply to the previous element to generate the next element
     * @return a stream of elements generated by the iteration
     * @throws IllegalArgumentException if the initial element, hasNext or f is null
     */
    public static <T> Stream<T> iterate(final T init, final Predicate<? super T> hasNext, final UnaryOperator<T> f) throws IllegalArgumentException {
        N.checkArgNotNull(init);
        N.checkArgNotNull(hasNext);
        N.checkArgNotNull(f);

        return of(new ObjIteratorEx<>() {
            private T cur = (T) NONE;
            private boolean hasMore = true;
            private boolean hasNextVal = false;

            @Override
            public boolean hasNext() {
                if (!hasNextVal && hasMore) {
                    hasNextVal = hasNext.test((cur = (cur == NONE ? init : f.apply(cur))));

                    if (!hasNextVal) {
                        hasMore = false;
                    }
                }

                return hasNextVal;
            }

            @Override
            public T next() {
                if (!hasNextVal && !hasNext()) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                hasNextVal = false;
                return cur;
            }
        });
    }

    /**
     * Creates a stream that iterates over elements starting from the given initial value.
     * This is a static factory method that creates an infinite stream through iterative function application.
     *
     * <p>Each subsequent element is generated by applying the provided unary operator to the previous element.
     * This creates an infinite stream, so it should be used with limiting operations like limit() or takeWhile().
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Stream<Integer> naturals = Stream.iterate(1, x -> x + 1);
     * naturals.limit(5).forEach(System.out::println);   // prints: 1, 2, 3, 4, 5
     * }</pre>
     *
     * @param <T> the type of the elements in the stream
     * @param init the initial element
     * @param f the function to apply to the previous element to produce the next element
     * @return a stream of elements generated by iterating with the given function
     * @throws IllegalArgumentException if the initial element or f is null
     */
    public static <T> Stream<T> iterate(final T init, final UnaryOperator<T> f) throws IllegalArgumentException {
        N.checkArgNotNull(init);
        N.checkArgNotNull(f);

        return of(new ObjIteratorEx<>() {
            private T cur = (T) NONE;

            @Override
            public boolean hasNext() {
                return true;
            }

            @Override
            public T next() { // NOSONAR
                return cur = (cur == NONE ? init : f.apply(cur));
            }
        });
    }

    /**
     * Generates a Stream using the provided Supplier.
     * This is a static factory method that creates an infinite stream from a supplier.
     *
     * <p>The supplier is used to generate each element of the stream. Since this creates an infinite stream,
     * it should be used with limiting operations like limit() or takeWhile().
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Stream<Double> randoms = Stream.generate(Math::random);
     * randoms.limit(3).forEach(System.out::println);   // prints 3 random numbers
     * }</pre>
     *
     * @param <T> the type of the elements in the stream
     * @param supplier the Supplier that provides the elements of the stream.
     * @return a Stream generated by the given supplier
     * @throws IllegalArgumentException if the supplier is null
     */
    public static <T> Stream<T> generate(final Supplier<T> supplier) throws IllegalArgumentException {
        N.checkArgNotNull(supplier, cs.supplier);

        return of(new ObjIteratorEx<>() {
            @Override
            public boolean hasNext() {
                return true;
            }

            @Override
            public T next() { // NOSONAR
                return supplier.get();
            }
        });
    }

    /**
     * Creates a stream of lines from the specified file.
     * This is a static factory method that creates a stream by reading a file line by line.
     *
     * <p>The file is read lazily - lines are read as the stream is consumed. The default charset is used.
     * The underlying file resources are automatically closed when the stream is closed.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * try (Stream<String> lines = Stream.ofLines(new File("data.txt"))) {
     *     lines.forEach(System.out::println);
     * }
     * }</pre>
     *
     * @param file the file to read lines from
     * @return a stream of lines from the file
     * @throws IllegalArgumentException if the file is {@code null}
     */
    public static Stream<String> ofLines(final File file) {
        return ofLines(file, Charsets.UTF_8);
    }

