    /**
     * Creates a stream of lines from the given Reader.
     * This is a static factory method that creates a stream by reading lines from a Reader.
     *
     * <p>The Reader is read lazily - lines are read as the stream is consumed.
     * It's the user's responsibility to close the input reader after the stream is completed.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Reader reader = new FileReader("data.txt");
     * Stream<String> lines = Stream.ofLines(reader);
     * lines.forEach(System.out::println);
     * reader.close();   // closes reader manually
     * }</pre>
     *
     * @param reader the Reader to read lines from
     * @return a Stream of lines read from the Reader
     * @throws IllegalArgumentException if the reader is {@code null}
     */
    public static Stream<String> ofLines(final Reader reader) {
        return ofLines(reader, false);
    }

    /**
     * Creates a stream of lines from the given Reader.
     * This is a static factory method that creates a stream by reading lines from a Reader with optional auto-closing.
     *
     * <p>The Reader is read lazily - lines are read as the stream is consumed.
     * If closeReaderWhenStreamIsClosed is {@code true}, the Reader will be automatically closed when the stream is closed.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * try (Stream<String> lines = Stream.ofLines(new FileReader("data.txt"), true)) {
     *     lines.map(String::toUpperCase)
     *         .forEach(System.out::println);
     * } // reader is automatically closed
     * }</pre>
     *
     * @param reader the Reader to read lines from
     * @param closeReaderWhenStreamIsClosed if {@code true}, the input Reader will be closed when the stream is closed
     * @return a Stream of lines read from the Reader
     * @throws IllegalArgumentException if the reader is null
     */
    public static Stream<String> ofLines(final Reader reader, final boolean closeReaderWhenStreamIsClosed) throws IllegalArgumentException {
        N.checkArgNotNull(reader, cs.reader);

        final ObjIteratorEx<String> iter = createLazyLineIterator(null, null, Charsets.UTF_8, reader, closeReaderWhenStreamIsClosed);

        if (closeReaderWhenStreamIsClosed) {
            return of(iter).onClose(iter::closeResource); //NOSONAR
        } else {
            return of(iter); //NOSONAR
        }
    }

    private static ObjIteratorEx<String> createLazyLineIterator(final File file, final Path path, final Charset charset, final Reader reader,
            final boolean closeReader) {
        return ObjIteratorEx.defer(new Supplier<ObjIteratorEx<String>>() {
            private ObjIteratorEx<String> lazyIter = null;

            @Override
            public synchronized ObjIteratorEx<String> get() {
                if (lazyIter == null) {
                    lazyIter = new ObjIteratorEx<>() {
                        private final BufferedReader bufferedReader;

                        { //NOSONAR
                            if (reader != null) {
                                bufferedReader = reader instanceof BufferedReader ? ((BufferedReader) reader) : new BufferedReader(reader);
                            } else if (file != null) {
                                bufferedReader = IOUtil.newBufferedReader(file, charset == null ? Charsets.UTF_8 : charset);
                            } else {
                                bufferedReader = IOUtil.newBufferedReader(path, charset == null ? Charsets.UTF_8 : charset);
                            }
                        }

                        private final LineIterator lineIterator = new LineIterator(bufferedReader);

                        @Override
                        public boolean hasNext() {
                            return lineIterator.hasNext();
                        }

                        @Override
                        public String next() {
                            return lineIterator.next();
                        }

                        @Override
                        public void closeResource() {
                            if (closeReader) {
                                IOUtil.closeQuietly(bufferedReader);
                            }
                        }
                    };
                }

                return lazyIter;
            }
        });
    }

    /**
     * Lists the files in the specified parent directory.
     * This is a static factory method that creates a stream of files from a directory.
     *
     * <p>Returns all files and subdirectories in the specified directory.
     * If the directory doesn't exist, an empty stream is returned.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * File dir = new File("/home/user");
     * Stream<File> files = Stream.listFiles(dir);
     * files.forEach(file -> System.out.println(file.getName()));
     * }</pre>
     *
     * @param parentPath the parent directory to list files from
     * @return a stream of files in the parent directory
     * @throws IllegalArgumentException if parentPath is {@code null}
     */
    public static Stream<File> listFiles(final File parentPath) {
        N.checkArgNotNull(parentPath, cs.parentPath);

        if (!parentPath.exists()) {
            return empty();
        }

        return of(parentPath.listFiles());
    }

    /**
     * Lists the files in the specified parent directory.
     * This is a static factory method that creates a stream of files from a directory with optional recursive traversal.
     *
     * <p>If recursively is {@code false}, returns only direct children of the directory.
     * If recursively is {@code true}, returns all files and directories in the entire directory tree.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * File dir = new File("/home/user");
     * Stream<File> allFiles = Stream.listFiles(dir, true);
     * allFiles.filter(File::isFile)
     *         .forEach(file -> System.out.println(file.getPath()));
     * }</pre>
     *
     * @param parentPath the parent directory to list files from
     * @param recursively if {@code true}, lists files recursively in sub-directories
     * @return a stream of files in the parent directory
     * @throws IllegalArgumentException if parentPath is {@code null}
     */
    public static Stream<File> listFiles(final File parentPath, final boolean recursively) {
        N.checkArgNotNull(parentPath, cs.parentPath);

        if (!parentPath.exists()) {
            return empty();
        } else if (!recursively) {
            return of(parentPath.listFiles());
        }

        final ObjIterator<File> iter = new ObjIterator<>() {
            private final Queue<File> paths = N.toLinkedList(parentPath);
            private File[] subFiles = null;
            private int cursor = 0;

            @Override
            public boolean hasNext() {
                if ((subFiles == null || cursor >= subFiles.length) && paths.size() > 0) {
                    cursor = 0;
                    subFiles = null;

                    while (paths.size() > 0) {
                        subFiles = paths.poll().listFiles();

                        if (N.notEmpty(subFiles)) {
                            break;
                        }
                    }
                }

                return subFiles != null && cursor < subFiles.length;
            }

            @Override
            public File next() {
                if (!hasNext()) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                if (subFiles[cursor].isDirectory()) {
                    paths.offer(subFiles[cursor]);
                }

                return subFiles[cursor++];
            }
        };

        return of(iter);
    }

    /**
     * Lists the files in the specified parent directory.
     * This is a static factory method that creates a stream of files with options for recursive traversal and filtering.
     *
     * <p>If recursively is {@code true}, traverses the entire directory tree.
     * If excludeDirectory is {@code true}, only regular files are included (directories are excluded).
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * File dir = new File("/home/user");
     * Stream<File> onlyFiles = Stream.listFiles(dir, true, true);
     * onlyFiles.filter(f -> f.getName().endsWith(".txt"))
     *          .forEach(System.out::println);   // prints all .txt files recursively
     * }</pre>
     *
     * @param parentPath the parent directory to list files from
     * @param recursively if {@code true}, lists files recursively in sub-directories
     * @param excludeDirectory if {@code true}, excludes directories from the stream
     * @return a stream of files in the parent directory
     * @throws IllegalArgumentException if parentPath is {@code null}
     */
    public static Stream<File> listFiles(final File parentPath, final boolean recursively, final boolean excludeDirectory) {
        if (excludeDirectory) {
            return listFiles(parentPath, recursively).filter(Fn.isFile());
        } else {
            return listFiles(parentPath, recursively);
        }
    }

    /**
     * Creates a stream that generates elements at fixed intervals.
     * This is a static factory method that creates a stream with timed element generation.
     *
     * <p>Elements are generated by the supplier at the specified interval in milliseconds.
     * This creates an infinite stream that should be used with limiting operations or closed when done.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Stream<String> timestamps = Stream.interval(1000, () -> new Date().toString());
     * timestamps.limit(5).forEach(System.out::println);   // prints timestamp every second, 5 times
     * }</pre>
     *
     * @param <T> the type of elements generated by the stream
     * @param intervalInMillis the interval in milliseconds between each element generation
     * @param s the supplier that generates the elements
     * @return a stream that generates elements at the specified interval
     * @throws IllegalArgumentException if the supplier is null
     */
    public static <T> Stream<T> interval(final long intervalInMillis, final Supplier<T> s) {
        return interval(0, intervalInMillis, s);
    }

