    /**
     * Observes a blocking queue and creates a stream that polls elements from the queue for the specified duration.
     * This is a static factory method that creates a stream from a blocking queue with time-based observation.
     *
     * <p>The stream will poll elements from the queue until the duration expires. Elements are retrieved
     * as they become available. This is useful for processing elements from concurrent producers.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * final BlockingQueue<String> queue = new ArrayBlockingQueue<>(32);
     * N.asyncExecute(() -> Stream.observe(queue, Duration.ofMillis(100))
     *     .filter(s -> s.startsWith("a"))
     *     .forEach(Fn.println()));
     * N.asList("a", "b", "ab", "bc", "1", "a").forEach(queue::add);
     * N.sleep(10);
     * N.println("==================");
     * N.sleep(100);
     * N.println("==================");
     * N.sleep(10);
     * }</pre>
     *
     * @param <T> the type of elements in the queue
     * @param queue the blocking queue to observe
     * @param duration the total time to observe the queue
     * @return a stream that polls elements from the queue until the duration expires
     * @throws IllegalArgumentException if the queue or duration is null
     */
    @Beta
    public static <T> Stream<T> observe(final BlockingQueue<T> queue, final Duration duration) throws IllegalArgumentException {
        N.checkArgNotNull(queue, cs.queue);
        N.checkArgNotNull(duration, cs.duration);

        final long now = System.currentTimeMillis();
        final long endTime = duration.toMillis() >= Long.MAX_VALUE - now ? Long.MAX_VALUE : now + duration.toMillis();

        final Iterator<T> iter = new ObjIterator<>() {
            private T next = null;

            @Override
            public boolean hasNext() {
                if (next == null) {
                    final long curTime = System.currentTimeMillis();

                    if (curTime <= endTime) {
                        try {
                            next = queue.poll(endTime - curTime, TimeUnit.MILLISECONDS);
                        } catch (final InterruptedException e) {
                            throw toRuntimeException(e);
                        }
                    }
                }

                return next != null;
            }

            @Override
            public T next() {
                if (!hasNext()) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                final T res = next;
                next = null;
                return res;
            }
        };

        return of(iter);
    }

    /**
     * Observes a blocking queue and creates a stream that polls elements from the queue at fixed intervals.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * final BlockingQueue<String> queue = new ArrayBlockingQueue<>(32);
     * final MutableBoolean hasMore = MutableBoolean.of(true);
     * N.asyncExecute(() -> Stream.observe(queue, () -> hasMore.value(), 10).filter(s -> s.startsWith("a")).forEach(Fn.println()));
     * N.asList("a", "b", "ab", "bc", "1", "a").forEach(queue::add);
     * N.println("==================");
     * hasMore.setFalse();
     * N.sleep(50);
     * N.println("==================");
     * }</pre>
     *
     * @param <T> the type of elements in the queue
     * @param queue the blocking queue to observe
     * @param hasMore a supplier that returns {@code true} if the upstream may still put more elements into the queue, or {@code false} if the upstream is completed.
     * @param maxWaitIntervalInMillis the maximum wait interval in milliseconds between polling the queue
     * @return a stream that polls elements from the queue at the specified interval
     * @throws IllegalArgumentException if the queue or hasMore is {@code null}, or if maxWaitIntervalInMillis is not positive (zero or negative)
     */
    @Beta
    public static <T> Stream<T> observe(final BlockingQueue<T> queue, final BooleanSupplier hasMore, final long maxWaitIntervalInMillis)
            throws IllegalArgumentException {
        N.checkArgNotNull(queue, cs.queue);
        N.checkArgNotNull(hasMore, cs.hasMore);
        N.checkArgPositive(maxWaitIntervalInMillis, cs.maxWaitIntervalInMillis);

        final Iterator<T> iter = new ObjIterator<>() {
            private T next = null;

            @Override
            public boolean hasNext() {
                if (next == null && (hasMore.getAsBoolean() || queue.size() > 0)) {
                    try {
                        do {
                            next = queue.poll(maxWaitIntervalInMillis, TimeUnit.MILLISECONDS);
                        } while (next == null && (hasMore.getAsBoolean() || queue.size() > 0));
                    } catch (final InterruptedException e) {
                        throw toRuntimeException(e);
                    }
                }

                return next != null;
            }

            @Override
            public T next() {
                if (!hasNext()) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                final T res = next;
                next = null;
                return res;
            }
        };

        return of(iter);
    }

    /**
     * Concatenates multiple arrays into a single stream.
     * This is a static factory method that creates a new stream containing all elements from the provided arrays in order.
     *
     * <p>The arrays are processed sequentially, maintaining the order of elements within each array
     * and the order of arrays as provided. If no arrays are provided, an empty stream is returned.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Integer[] arr1 = {1, 2, 3};
     * Integer[] arr2 = {4, 5};
     * Stream.concat(arr1, arr2)
     *       .toList();                    // returns [1, 2, 3, 4, 5]
     * Stream.<Integer>concat().count();   // returns 0
     * }</pre>
     *
     * @param <T> the type of elements in the arrays
     * @param a the arrays to be concatenated. Can be empty or contain {@code null} arrays (which are treated as empty)
     * @return a stream containing all the elements of the provided arrays
     * @see #concat(Iterable...)
     * @see #concat(Iterator...)
     * @see #concat(Stream...)
     */
    @SafeVarargs
    public static <T> Stream<T> concat(final T[]... a) {
        if (N.isEmpty(a)) {
            return empty();
        }

        return of(Iterators.concat(a));
    }

