    /**
     * Concatenates multiple iterables from a collection into a single stream.
     * This is a static factory method that creates a new stream containing all elements from the provided iterables in order.
     *
     * <p>The iterables are processed sequentially, maintaining the order of elements within each iterable
     * and the order of iterables as provided in the collection. If the collection is empty, an empty stream is returned.
     * This method is marked as @Beta, indicating it may be subject to changes in future versions.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * List<List<Integer>> lists = Arrays.asList(
     *     Arrays.asList(1, 2),
     *     Arrays.asList(3, 4, 5)
     * );
     * Stream.concatIterables(lists)
     *       .toList();   // returns [1, 2, 3, 4, 5]
     * }</pre>
     *
     * @param <T> the type of elements in the iterables
     * @param iterables the collection of iterables to be concatenated. Can be empty or contain {@code null} iterables (which are treated as empty)
     * @return a stream containing all the elements of the provided iterables
     * @see #concat(Iterable...)
     * @see #concatIterators(Collection)
     */
    @Beta
    public static <T> Stream<T> concatIterables(final Collection<? extends Iterable<? extends T>> iterables) {
        if (N.isEmpty(iterables)) {
            return empty();
        }

        return of(new ObjIteratorEx<>() {
            private final Iterator<? extends Iterable<? extends T>> iterators = iterables.iterator();
            private Iterable<? extends T> coll;
            private Iterator<? extends T> cur;

            @Override
            public boolean hasNext() {
                while ((cur == null || !cur.hasNext()) && iterators.hasNext()) {
                    cur = (coll = iterators.next()) == null ? null : coll.iterator();
                }

                return cur != null && cur.hasNext();
            }

            @Override
            public T next() {
                if ((cur == null || !cur.hasNext()) && !hasNext()) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                return cur.next();
            }
        });
    }

