    /**
     * Zips two char iterators into a single stream by combining corresponding elements.
     * The resulting stream ends when either of the input iterators runs out of elements.
     *
     * <p>This is a static factory method that creates a new stream where each element
     * is produced by applying the zip function to the corresponding elements from the two iterators.
     * The iterators are consumed as the stream is processed.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * CharIterator iter1 = CharIterator.of('a', 'b', 'c');
     * CharIterator iter2 = CharIterator.of('x', 'y', 'z');
     * Stream.zip(iter1, iter2, (a, b) -> "" + a + b)
     *       .toList();   // returns ["ax", "by", "cz"]
     * }</pre>
     *
     * @param <R> the type of the result elements
     * @param a the first char iterator. Can be {@code null} (treated as empty)
     * @param b the second char iterator. Can be {@code null} (treated as empty)
     * @param zipFunction the function to combine elements from the two iterators
     * @return a stream of combined values
     */
    public static <R> Stream<R> zip(final CharIterator a, final CharIterator b, final CharBiFunction<? extends R> zipFunction) {
        return new IteratorStream<>(new ObjIteratorEx<>() {
            private final CharIterator iterA = a == null ? CharIterator.empty() : a;
            private final CharIterator iterB = b == null ? CharIterator.empty() : b;

            @Override
            public boolean hasNext() {
                return iterA.hasNext() && iterB.hasNext();
            }

            @Override
            public R next() {
                return zipFunction.apply(iterA.nextChar(), iterB.nextChar());
            }
        });
    }

