    /**
     * Zips two character iterators into a single stream until all of them run out of values.
     * This is a static factory method that combines elements from two character iterators using a zip function.
     *
     * <p>The operation continues until both iterators are exhausted. When one iterator runs out of values,
     * the specified default value (valueForNoneA or valueForNoneB) is used for that iterator.
     * Null iterators are treated as empty iterators.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * CharIterator a = CharIterator.of('a', 'b', 'c');
     * CharIterator b = CharIterator.of('x', 'y');
     * Stream.zip(a, b, '0', '1', (x, y) -> "" + x + y)
     *       .toList();   // returns ["ax", "by", "c1"]
     * }</pre>
     *
     * @param <R> the type of the result elements
     * @param a the first character iterator, may be {@code null} (treated as empty)
     * @param b the second character iterator, may be {@code null} (treated as empty)
     * @param valueForNoneA the default value to use when the first iterator runs out of values
     * @param valueForNoneB the default value to use when the second iterator runs out of values
     * @param zipFunction the function to combine pairs of values from the iterators.
     * @return a stream of combined values
     */
    public static <R> Stream<R> zip(final CharIterator a, final CharIterator b, final char valueForNoneA, final char valueForNoneB,
            final CharBiFunction<? extends R> zipFunction) {
        return new IteratorStream<>(new ObjIteratorEx<>() {
            private final CharIterator iterA = a == null ? CharIterator.empty() : a;
            private final CharIterator iterB = b == null ? CharIterator.empty() : b;

            @Override
            public boolean hasNext() {
                return iterA.hasNext() || iterB.hasNext();
            }

            @Override
            public R next() {
                if (iterA.hasNext()) {
                    return zipFunction.apply(iterA.nextChar(), iterB.hasNext() ? iterB.nextChar() : valueForNoneB);
                } else {
                    return zipFunction.apply(valueForNoneA, iterB.nextChar());
                }
            }
        });
    }

    /**
     * Zips three character iterators into a single stream until all of them run out of values.
     * This is a static factory method that combines elements from three character iterators using a zip function.
     *
     * <p>The operation continues until all iterators are exhausted. When an iterator runs out of values,
     * the specified default value (valueForNoneA, valueForNoneB, or valueForNoneC) is used for that iterator.
     * Null iterators are treated as empty iterators.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * CharIterator a = CharIterator.of('a', 'b');
     * CharIterator b = CharIterator.of('x', 'y', 'z');
     * CharIterator c = CharIterator.of('1');
     * Stream.zip(a, b, c, '0', '0', '0', (x, y, z) -> "" + x + y + z)
     *       .toList();   // returns ["ax1", "by0", "0z0"]
     * }</pre>
     *
     * @param <R> the type of the result elements
     * @param a the first character iterator, may be {@code null} (treated as empty)
     * @param b the second character iterator, may be {@code null} (treated as empty)
     * @param c the third character iterator, may be {@code null} (treated as empty)
     * @param valueForNoneA the default value to use when the first iterator runs out of values
     * @param valueForNoneB the default value to use when the second iterator runs out of values
     * @param valueForNoneC the default value to use when the third iterator runs out of values
     * @param zipFunction the function to combine triples of values from the iterators.
     * @return a stream of combined values
     */
    public static <R> Stream<R> zip(final CharIterator a, final CharIterator b, final CharIterator c, final char valueForNoneA, final char valueForNoneB,
            final char valueForNoneC, final CharTriFunction<? extends R> zipFunction) {
        return new IteratorStream<>(new ObjIteratorEx<>() {
            private final CharIterator iterA = a == null ? CharIterator.empty() : a;
            private final CharIterator iterB = b == null ? CharIterator.empty() : b;
            private final CharIterator iterC = c == null ? CharIterator.empty() : c;

            @Override
            public boolean hasNext() {
                return iterA.hasNext() || iterB.hasNext() || iterC.hasNext();
            }

            @Override
            public R next() {
                if (iterA.hasNext()) {
                    return zipFunction.apply(iterA.nextChar(), iterB.hasNext() ? iterB.nextChar() : valueForNoneB,
                            iterC.hasNext() ? iterC.nextChar() : valueForNoneC);
                } else if (iterB.hasNext()) {
                    return zipFunction.apply(valueForNoneA, iterB.nextChar(), iterC.hasNext() ? iterC.nextChar() : valueForNoneC);
                } else {
                    return zipFunction.apply(valueForNoneA, valueForNoneB, iterC.nextChar());
                }
            }
        });
    }

