    /**
     * Zips a collection of byte streams into a single stream until one of them runs out of values.
     * This is a static factory method that combines elements from multiple byte streams using a zip function.
     *
     * <p>The operation stops when any stream runs out of values. No default values are used
     * for the shorter streams. The returned stream will handle closing of all input streams when it is closed.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * List<ByteStream> streams = Arrays.asList(
     *     ByteStream.of((byte)1, (byte)2),
     *     ByteStream.of((byte)10, (byte)20),
     *     ByteStream.of((byte)100, (byte)50)
     * );
     * Stream.zip(streams, bytes -> bytes[0] + bytes[1] + bytes[2])
     *       .toList();   // returns [111, 72]
     * }</pre>
     *
     * @param <R> the type of the result elements
     * @param c the collection of byte streams to zip
     * @param zipFunction the function to combine arrays of values from the streams.
     * @return a stream of combined values that will close all input streams when closed
     */
    public static <R> Stream<R> zip(final Collection<? extends ByteStream> c, final ByteNFunction<? extends R> zipFunction) {
        if (N.isEmpty(c)) {
            return Stream.empty();
        }

        final int len = c.size();
        final ByteIterator[] iters = new ByteIterator[len];
        int i = 0;

        for (final ByteStream s : c) {
            iters[i++] = iterate(s);
        }

        return new IteratorStream<>(new ObjIteratorEx<R>() {
            @Override
            public boolean hasNext() {
                for (int i = 0; i < len; i++) {
                    if (!iters[i].hasNext()) {
                        return false;
                    }
                }

                return true;
            }

            @Override
            public R next() {
                final byte[] args = new byte[len];

                for (int i = 0; i < len; i++) {
                    args[i] = iters[i].nextByte();
                }

                return zipFunction.apply(args);
            }
        }).onClose(newCloseHandler(c));
    }

