    /**
     * Zips a collection of byte streams into a single stream until all of them run out of values.
     * This is a static factory method that combines elements from multiple byte streams using a zip function.
     *
     * <p>The operation continues until all streams are exhausted. When a stream runs out of values,
     * the corresponding default value from valuesForNone array is used for that stream.
     * The returned stream will handle closing of all input streams when it is closed.
     *
     * <p>The size of valuesForNone must equal the size of the streams collection.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * List<ByteStream> streams = Arrays.asList(
     *     ByteStream.of((byte)1, (byte)2),
     *     ByteStream.of((byte)10, (byte)20, (byte)30),
     *     ByteStream.of((byte)100)
     * );
     * byte[] defaults = {0, 1, 2};
     * Stream.zip(streams, defaults, bytes -> bytes[0] + bytes[1] + bytes[2])
     *       .toList();   // returns [111, 24, 32]
     * }</pre>
     *
     * @param <R> the type of the result elements
     * @param c the collection of byte streams to zip
     * @param valuesForNone array of default values, must have same size as streams collection
     * @param zipFunction the function to combine arrays of values from the streams.
     * @return a stream of combined values that will close all input streams when closed
     * @throws IllegalArgumentException if the size of valuesForNone doesn't match the size of streams collection
     */
    public static <R> Stream<R> zip(final Collection<? extends ByteStream> c, final byte[] valuesForNone, final ByteNFunction<? extends R> zipFunction) {
        if (N.isEmpty(c)) {
            return Stream.empty();
        }

        final int len = c.size();

        if (len != valuesForNone.length) {
            throw new IllegalArgumentException("The size of 'valuesForNone' must match the size of the input collection");
        }

        final ByteStream[] ss = c.toArray(new ByteStream[len]);
        final ByteIterator[] iters = new ByteIterator[len];

        for (int i = 0; i < len; i++) {
            iters[i] = iterate(ss[i]);
        }

        return new IteratorStream<>(new ObjIteratorEx<R>() {
            @Override
            public boolean hasNext() {
                for (int i = 0; i < len; i++) {
                    if (iters[i] != null) {
                        if (iters[i].hasNext()) {
                            return true;
                        } else {
                            iters[i] = null;
                            ss[i].close();
                        }
                    }
                }

                return false;
            }

            @Override
            public R next() {
                final byte[] args = new byte[len];
                boolean hasNext = false;

                for (int i = 0; i < len; i++) {
                    if (iters[i] != null && iters[i].hasNext()) {
                        hasNext = true;
                        args[i] = iters[i].nextByte();
                    } else {
                        args[i] = valuesForNone[i];
                    }
                }

                if (!hasNext) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                return zipFunction.apply(args);
            }
        }).onClose(newCloseHandler(c));
    }

