    public static <R> Stream<R> zip(final Collection<? extends LongStream> c, final long[] valuesForNone, final LongNFunction<? extends R> zipFunction) {
        if (N.isEmpty(c)) {
            return Stream.empty();
        }

        final int len = c.size();

        if (len != valuesForNone.length) {
            throw new IllegalArgumentException("The size of 'valuesForNone' must match the size of the input collection");
        }

        final LongStream[] ss = c.toArray(new LongStream[len]);
        final LongIterator[] iters = new LongIterator[len];

        for (int i = 0; i < len; i++) {
            iters[i] = iterate(ss[i]);
        }

        return new IteratorStream<>(new ObjIteratorEx<R>() {
            @Override
            public boolean hasNext() {
                for (int i = 0; i < len; i++) {
                    if (iters[i] != null) {
                        if (iters[i].hasNext()) {
                            return true;
                        } else {
                            iters[i] = null;
                            ss[i].close();
                        }
                    }
                }

                return false;
            }

            @Override
            public R next() {
                final long[] args = new long[len];
                boolean hasNext = false;

                for (int i = 0; i < len; i++) {
                    if (iters[i] != null && iters[i].hasNext()) {
                        hasNext = true;
                        args[i] = iters[i].nextLong();
                    } else {
                        args[i] = valuesForNone[i];
                    }
                }

                if (!hasNext) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                return zipFunction.apply(args);
            }
        }).onClose(newCloseHandler(c));
    }

