    /**
     * Zips a collection of float streams into a single stream until one of them runs out of values.
     * Each set of values is combined into a single value using the supplied zipFunction.
     *
     * <p>This method processes elements from all streams in parallel positions and stops when
     * any stream is exhausted. The resulting stream will close all input streams when it is closed.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * List<FloatStream> streams = Arrays.asList(
     *     FloatStream.of(1.0f, 2.0f),
     *     FloatStream.of(3.0f, 4.0f, 5.0f),
     *     FloatStream.of(6.0f, 7.0f)
     * );
     * Stream.zip(streams, args -> args[0] + args[1] + args[2])
     *       .toList();   // returns [10.0f, 13.0f]
     * }</pre>
     *
     * @param <R> the type of the result
     * @param c the collection of float streams
     * @param zipFunction the function to combine sets of values from the streams.
     * @return a stream of combined values that will close all input streams when closed
     */
    public static <R> Stream<R> zip(final Collection<? extends FloatStream> c, final FloatNFunction<? extends R> zipFunction) {
        if (N.isEmpty(c)) {
            return Stream.empty();
        }

        final int len = c.size();
        final FloatIterator[] iters = new FloatIterator[len];
        int i = 0;

        for (final FloatStream s : c) {
            iters[i++] = iterate(s);
        }

        return new IteratorStream<>(new ObjIteratorEx<R>() {
            @Override
            public boolean hasNext() {
                for (int i = 0; i < len; i++) {
                    if (!iters[i].hasNext()) {
                        return false;
                    }
                }

                return true;
            }

            @Override
            public R next() {
                final float[] args = new float[len];

                for (int i = 0; i < len; i++) {
                    args[i] = iters[i].nextFloat();
                }

                return zipFunction.apply(args);
            }
        }).onClose(newCloseHandler(c));
    }

