    /**
     * Zips a collection of float streams into a single stream until all of them run out of values.
     * Each set of values is combined into a single value using the supplied zipFunction.
     * If one stream runs out of values before the others, the specified valuesForNone are used.
     *
     * <p>This method continues processing until all streams are exhausted, using the corresponding
     * default value from valuesForNone when a stream is exhausted. The resulting stream will close
     * all input streams when it is closed.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * List<FloatStream> streams = Arrays.asList(
     *     FloatStream.of(1.0f, 2.0f),
     *     FloatStream.of(3.0f, 4.0f, 5.0f),
     *     FloatStream.of(6.0f)
     * );
     * float[] defaults = {0.0f, 0.0f, 0.0f};
     * Stream.zip(streams, defaults, args -> args[0] + args[1] + args[2])
     *       .toList();   // returns [10.0f, 6.0f, 5.0f]
     * }</pre>
     *
     * @param <R> the type of the result
     * @param c the collection of float streams
     * @param valuesForNone the values to use if the streams run out of values. Must have the same size as the collection.
     * @param zipFunction the function to combine sets of values from the streams.
     * @return a stream of combined values that will close all input streams when closed
     * @throws IllegalArgumentException if the size of valuesForNone doesn't match the size of the collection
     */
    public static <R> Stream<R> zip(final Collection<? extends FloatStream> c, final float[] valuesForNone, final FloatNFunction<? extends R> zipFunction) {
        if (N.isEmpty(c)) {
            return Stream.empty();
        }

        final int len = c.size();

        if (len != valuesForNone.length) {
            throw new IllegalArgumentException("The size of 'valuesForNone' must match the size of the input collection");
        }

        final FloatStream[] ss = c.toArray(new FloatStream[len]);
        final FloatIterator[] iters = new FloatIterator[len];

        for (int i = 0; i < len; i++) {
            iters[i] = iterate(ss[i]);
        }

        return new IteratorStream<>(new ObjIteratorEx<R>() {
            @Override
            public boolean hasNext() {
                for (int i = 0; i < len; i++) {
                    if (iters[i] != null) {
                        if (iters[i].hasNext()) {
                            return true;
                        } else {
                            iters[i] = null;
                            ss[i].close();
                        }
                    }
                }

                return false;
            }

            @Override
            public R next() {
                final float[] args = new float[len];
                boolean hasNext = false;

                for (int i = 0; i < len; i++) {
                    if (iters[i] != null && iters[i].hasNext()) {
                        hasNext = true;
                        args[i] = iters[i].nextFloat();
                    } else {
                        args[i] = valuesForNone[i];
                    }
                }

                if (!hasNext) {
                    throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                }

                return zipFunction.apply(args);
            }
        }).onClose(newCloseHandler(c));
    }

