    /**
     * Zips a collection of double streams into a single stream until one of them runs out of values.
     * Each set of values is combined into a single value using the supplied zipFunction.
     *
     * <p>This method processes elements from all streams in parallel positions and stops when
     * any stream is exhausted. The resulting stream will close all input streams when it is closed.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * List<DoubleStream> streams = Arrays.asList(
     *     DoubleStream.of(1.0, 2.0),
     *     DoubleStream.of(3.0, 4.0, 5.0),
     *     DoubleStream.of(6.0, 7.0)
     * );
     * Stream.zip(streams, args -> args[0] + args[1] + args[2])
     *       .toList();   // returns [10.0, 13.0]
     * }</pre>
     *
     * @param <R> the type of the result
     * @param c the collection of double streams
     * @param zipFunction the function to combine sets of values from the streams.
     * @return a stream of combined values that will close all input streams when closed
     */
    public static <R> Stream<R> zip(final Collection<? extends DoubleStream> c, final DoubleNFunction<? extends R> zipFunction) {
        if (N.isEmpty(c)) {
            return Stream.empty();
        }

        final int len = c.size();
        final DoubleIterator[] iters = new DoubleIterator[len];
        int i = 0;

        for (final DoubleStream s : c) {
            iters[i++] = iterate(s);
        }

        return new IteratorStream<>(new ObjIteratorEx<R>() {
            @Override
            public boolean hasNext() {
                for (int i = 0; i < len; i++) {
                    if (!iters[i].hasNext()) {
                        return false;
                    }
                }

                return true;
            }

            @Override
            public R next() {
                final double[] args = new double[len];

                for (int i = 0; i < len; i++) {
                    args[i] = iters[i].nextDouble();
                }

                return zipFunction.apply(args);
            }
        }).onClose(newCloseHandler(c));
    }

