    /**
     * Zips three iterators into a single stream until one of them runs out of values in parallel.
     * Each triplet of values is combined into a single value by the provided zipFunction, which will be executed by multiple threads.
     * The iteration stops when any iterator runs out of elements.
     *
     * <p>This is a parallel operation where the zipFunction is executed concurrently by multiple threads.
     * The order of elements in the resulting stream is NOT guaranteed to match the input order: with more than one thread,
     * results are emitted in the order their {@code zipFunction} computations complete. Pass {@code maxThreadNumForZipFunction == 1}
     * (or use the sequential {@code zip(...)}) if the original positional order must be preserved.
     * If maxThreadNumForZipFunction is 1, this method behaves the same as the sequential zip operation.
     *
     * <p><b>Usage Examples:</b></p>
     * <pre>{@code
     * Iterator<Integer> iter1 = Arrays.asList(1, 2, 3).iterator();
     * Iterator<Integer> iter2 = Arrays.asList(10, 20).iterator();
     * Iterator<Integer> iter3 = Arrays.asList(100, 200, 300).iterator();
     * Stream.parallelZip(iter1, iter2, iter3, (a, b, c) -> a + b + c, 3)
     *       .toList();   // contains [111, 222], order may vary with multiple threads
     * }</pre>
     *
     * @param <A> the type of the elements in the first iterator
     * @param <B> the type of the elements in the second iterator
     * @param <C> the type of the elements in the third iterator
     * @param <R> the type of the result
     * @param a the first iterator. Can be {@code null} (treated as empty).
     * @param b the second iterator. Can be {@code null} (treated as empty).
     * @param c the third iterator. Can be {@code null} (treated as empty).
     * @param zipFunction the function to combine triplets of values from the iterators.
     * @param maxThreadNumForZipFunction the max thread number for executing the zipFunction. Must be positive.
     * @return a stream of combined values
     * @throws IllegalArgumentException if maxThreadNumForZipFunction is not positive
     */
    public static <A, B, C, R> Stream<R> parallelZip(final Iterator<? extends A> a, final Iterator<? extends B> b, final Iterator<? extends C> c,
            final TriFunction<? super A, ? super B, ? super C, ? extends R> zipFunction, final int maxThreadNumForZipFunction) {
        N.checkArgPositive(maxThreadNumForZipFunction, cs.maxThreadNumForZipFunction);

        if (maxThreadNumForZipFunction == 1) {
            return zip(a, b, c, zipFunction);
        }

        final Supplier<Stream<R>> supplier = () -> {
            final Iterator<A> iterA = a == null ? ObjIterator.empty() : (Iterator<A>) a;
            final Iterator<B> iterB = b == null ? ObjIterator.empty() : (Iterator<B>) b;
            final Iterator<C> iterC = c == null ? ObjIterator.empty() : (Iterator<C>) c;
            final int maxThreadNum = checkMaxThreadNum(maxThreadNumForZipFunction, DEFAULT_ASYNC_EXECUTOR);
            final List<Iterator<R>> iters = new ArrayList<>(maxThreadNum);
            final MutableBoolean onGoing = MutableBoolean.of(true);

            for (int i = 0; i < maxThreadNum; i++) {
                final ObjIteratorEx<R> iter = new ObjIteratorEx<>() {
                    private A nextA = null;
                    private B nextB = null;
                    private C nextC = null;
                    private boolean hasNext = false;

                    @Override
                    public boolean hasNext() {
                        if (!hasNext && onGoing.isTrue()) {
                            synchronized (iters) {
                                if (iterA.hasNext()) {
                                    nextA = iterA.next();
                                } else {
                                    onGoing.setFalse();
                                    return false;
                                }

                                if (iterB.hasNext()) {
                                    nextB = iterB.next();
                                } else {
                                    onGoing.setFalse();
                                    return false;
                                }

                                if (iterC.hasNext()) {
                                    nextC = iterC.next();
                                } else {
                                    onGoing.setFalse();
                                    return false;
                                }

                                hasNext = true;
                            }
                        }

                        return hasNext;
                    }

                    @Override
                    public R next() {
                        if (!hasNext()) {
                            throw new NoSuchElementException(ERROR_MSG_FOR_NO_SUCH_EX);
                        }

                        hasNext = false;
                        return zipFunction.apply(nextA, nextB, nextC);
                    }
                };

                iters.add(iter);
            }

            return new IteratorStream<>(parallelConcatIterators(iters, iters.size(), false, DEFAULT_ASYNC_EXECUTOR), false, null, null);
        };

        //noinspection resource
        return just(supplier).flatMap(Supplier::get);
    }

